import os, fnmatch
 
class UploadHandler(object):
 
    def getUploadedFilesInDirectory(self, path, match='*.*'):
        return [f for f in os.listdir(path) if fnmatch.fnmatch(f, match)]
    #return [os.path.join(root, name) for root, dirs, files in os.walk(path) for name in files]
    
    def getFilesFromLegacyNamesInDirectory(self, path):
        legacyNames = ['sample.jpg','sample.txt','sample.html']
        allFiles = self.getUploadedFilesInDirectory(path, '*.*')
        return [i for i in legacyNames if i not in  allFiles]
        
